import { useState, useEffect } from 'react';
import axios from 'axios';
import { API_URL } from '../constants';
import { useTranslation } from '../context/LanguageContext';
import { Search, History, Download, FileText, ChevronDown, ChevronUp } from 'lucide-react';
import * as XLSX from 'xlsx';

export default function DebtTracker() {
  const [clients, setClients] = useState([]);
  const [search, setSearch] = useState('');
  const [selectedClient, setSelectedClient] = useState(null);
  const [history, setHistory] = useState({ orders: [], payments: [] });
  const [loadingHistory, setLoadingHistory] = useState(false);
  const { t } = useTranslation();

  useEffect(() => {
    fetchClients();
  }, []);

  const fetchClients = async () => {
    const res = await axios.get(`${API_URL}/clients`);
    setClients(res.data);
  };

  const loadHistory = async (client) => {
    if (selectedClient?.id === client.id) {
      setSelectedClient(null);
      return;
    }
    setLoadingHistory(true);
    setSelectedClient(client);
    try {
      const res = await axios.get(`${API_URL}/clients/${client.id}/history`);
      setHistory(res.data);
    } catch (e) {
      alert("Tarixni olib bo'lmadi");
    }
    setLoadingHistory(false);
  };

  const exportSverka = () => {
    if (!selectedClient) return;
    const rows = [
      ...history.orders.map(o => ({ 
        date: new Date(o.createdAt), 
        desc: `Zakas #${o.orderNumber || o.id.substring(0,6)}`, 
        debit: o.amount, credit: 0 
      })),
      ...history.payments.filter(p => p.status === 'CONFIRMED').map(p => ({ 
        date: new Date(p.date || p.createdAt), 
        desc: `To'lov: ${p.paymentMethod}`, 
        debit: 0, credit: p.amount 
      }))
    ].sort((a, b) => a.date - b.date);

    let balance = 0;
    const data = rows.map(r => {
      balance += (r.debit - r.credit);
      return {
        'Sana': r.date.toLocaleString(),
        'Izoh': r.desc,
        'Olingan Tovar ($)': r.debit,
        'To\'langan Pul ($)': r.credit,
        'Qoldiq ($)': balance
      };
    });

    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Sverka");
    XLSX.writeFile(wb, `Sverka_${selectedClient.name}.xlsx`);
  };

  const filtered = clients.filter(c => 
    c.name.toLowerCase().includes(search.toLowerCase()) || 
    (c.customId && c.customId.includes(search))
  );

  const totalDebt = filtered.reduce((sum, c) => sum + (c.currentDebt > 0 ? c.currentDebt : 0), 0);
  const totalPrepayment = filtered.reduce((sum, c) => sum + (c.currentDebt < 0 ? Math.abs(c.currentDebt) : 0), 0);

  return (
    <div className="animate-fade-in">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '25px', flexWrap: 'wrap', gap: '15px' }}>
        <h2>≡ƒôë {t('debt')}</h2>
        <div style={{ position: 'relative', width: '300px' }}>
          <Search size={18} style={{ position: 'absolute', top: '12px', left: '15px', color: 'var(--text-muted)' }} />
          <input type="text" className="form-control" style={{ paddingLeft: '45px', borderRadius: '20px' }} placeholder={t('search')} value={search} onChange={(e) => setSearch(e.target.value)} />
        </div>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '20px', marginBottom: '30px' }}>
        <div className="card glass-panel" style={{ textAlign: 'center' }}>
          <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)', textTransform: 'uppercase', marginBottom: '5px' }}>{t('pending_debt')}</div>
          <div style={{ fontSize: '1.8rem', fontWeight: 'bold', color: 'var(--danger)' }}>${totalDebt.toLocaleString()}</div>
        </div>
        <div className="card glass-panel" style={{ textAlign: 'center' }}>
          <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)', textTransform: 'uppercase', marginBottom: '5px' }}>Haqdorlik (Kredit)</div>
          <div style={{ fontSize: '1.8rem', fontWeight: 'bold', color: 'var(--success)' }}>${totalPrepayment.toLocaleString()}</div>
        </div>
      </div>

      <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
        {filtered.map(c => (
          <div key={c.id} className="card" style={{ padding: '0', overflow: 'hidden' }}>
            <div 
              style={{ display: 'flex', justifyContent: 'space-between', padding: '15px 25px', alignItems: 'center', cursor: 'pointer' }}
              onClick={() => loadHistory(c)}
            >
              <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
                 {selectedClient?.id === c.id ? <ChevronUp/> : <ChevronDown/>}
                 <div>
                    <div style={{ fontWeight: 'bold', fontSize: '1.1rem' }}>{c.name}</div>
                    <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>Limit: ${c.creditLimit} | {c.phone}</div>
                 </div>
              </div>
              <div style={{ textAlign: 'right' }}>
                <div style={{ fontSize: '1.3rem', fontWeight: 'bold', color: c.currentDebt > 0 ? 'var(--danger)' : 'var(--success)' }}>
                  ${c.currentDebt?.toLocaleString()}
                </div>
              </div>
            </div>

            {selectedClient?.id === c.id && (
              <div className="animate-fade-in" style={{ padding: '20px', background: 'rgba(0,0,0,0.1)', borderTop: '1px solid rgba(255,255,255,0.05)' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '15px' }}>
                  <h4>≡ƒôè {t('debt')} (AKT)</h4>
                  <button onClick={exportSverka} className="btn btn-secondary" style={{ padding: '8px 15px' }}><Download size={16}/> {t('excel_export')}</button>
                </div>
                
                {loadingHistory ? <div style={{ textAlign: 'center', padding: '20px' }}>{t('loading')}</div> : (
                  <div className="responsive-grid">
                     <div className="card">
                        <h5 style={{ color: 'var(--warning)', marginBottom: '10px' }}>{t('orders')}</h5>
                        {history.orders.map(o => (
                          <div key={o.id} style={{ display: 'flex', justifyContent: 'space-between', padding: '10px 0', borderBottom: '1px solid var(--border-color)' }}>
                            <span>#{o.orderNumber || o.id.substring(0,6)} <small style={{ color: 'var(--text-muted)' }}>({new Date(o.createdAt).toLocaleDateString()})</small></span>
                            <span style={{ color: 'var(--danger)', fontWeight: 'bold' }}>+${o.amount}</span>
                          </div>
                        ))}
                     </div>
                     <div className="card">
                        <h5 style={{ color: 'var(--success)', marginBottom: '10px' }}>{t('payments')}</h5>
                        {history.payments.filter(p => p.status === 'CONFIRMED').map(p => (
                          <div key={p.id} style={{ display: 'flex', justifyContent: 'space-between', padding: '10px 0', borderBottom: '1px solid var(--border-color)' }}>
                            <span>{p.paymentMethod} <small style={{ color: 'var(--text-muted)' }}>({new Date(p.date || p.createdAt).toLocaleDateString()})</small></span>
                            <span style={{ color: 'var(--success)', fontWeight: 'bold' }}>-${p.amount}</span>
                          </div>
                        ))}
                     </div>
                  </div>
                )}
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import axios from 'axios';
import { API_URL } from '../constants';
import { useTranslation } from '../context/LanguageContext';
import { ShoppingCart, Search, Plus, Trash2, Send, Box, ChevronDown, ChevronUp } from 'lucide-react';

export default function NewOrder() {
  const [clients, setClients] = useState([]);
  const [products, setProducts] = useState([]);
  const [cart, setCart] = useState([]);
  const [search, setSearch] = useState('');
  const [selectedProductId, setSelectedProductId] = useState(null);
  const [selectedClient, setSelectedClient] = useState('');
  const [loading, setLoading] = useState(false);
  const { t } = useTranslation();

  useEffect(() => {
    setLoading(true);
    Promise.all([
      axios.get(`${API_URL}/clients`),
      axios.get(`${API_URL}/products`)
    ]).then(([cRes, pRes]) => {
      setClients(cRes.data || []);
      setProducts(pRes.data || []);
      setLoading(false);
    }).catch(() => setLoading(false));
  }, []);

  const addToCart = (e, p) => {
    e.stopPropagation();
    if (p.stock <= 0) return alert(t('no_stock'));
    const existing = cart.find(item => item.productId === p.id);
    if (existing) {
      if (existing.quantity >= p.stock) return alert(t('no_stock'));
      setCart(cart.map(item => item.productId === p.id ? { ...item, quantity: item.quantity + 1 } : item));
    } else {
      setCart([...cart, { productId: p.id, name: p.name, price: p.sellPrice, quantity: 1, stock: p.stock }]);
    }
  };

  const updateQty = (id, q) => {
    const item = cart.find(i => i.productId === id);
    if (q > item.stock) return alert(t('no_stock'));
    if (q <= 0) return removeFromCart(id);
    setCart(cart.map(i => i.productId === id ? { ...i, quantity: Number(q) } : i));
  };

  const removeFromCart = (id) => setCart(cart.filter(i => i.productId !== id));
  const total = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  const submitOrder = async () => {
    if (!selectedClient) return alert(t('client') + " tanlang!");
    if (cart.length === 0) return alert(t('empty_cart'));
    setLoading(true);
    try {
      await axios.post(`${API_URL}/orders`, {
        clientId: selectedClient,
        items: cart.map(i => ({ productId: i.productId, quantity: i.quantity, price: i.price }))
      });
      alert(t('order_success'));
      setCart([]); setSelectedClient('');
    } catch (err) { alert("Xato: " + (err.response?.data?.error || "Yuborib bo'lmadi")); }
    setLoading(false);
  };

  const s = search.toLowerCase();
  const filteredProducts = products.filter(p => 
    String(p.name || '').toLowerCase().includes(s) || 
    String(p.code || '').toLowerCase().includes(s) ||
    String(p.group || '').toLowerCase().includes(s)
  );

  const groupedProducts = filteredProducts.reduce((acc, p) => {
    const g = p.group || 'Boshqa';
    if (!acc[g]) acc[g] = [];
    acc[g].push(p);
    return acc;
  }, {});

  const groups = Object.keys(groupedProducts).sort();

  return (
    <div className="animate-fade-in">
      <h2 style={{ marginBottom: '20px' }}>≡ƒ¢Æ {t('new_order')}</h2>
      
      <div className="responsive-grid">
        <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
          {/* Client select compact */}
          <div className="card" style={{ padding: '15px' }}>
            <h4 style={{ marginBottom: '10px', fontSize: '1rem' }}>1. {t('client')}</h4>
            <select className="form-control" style={{ height: '40px', fontSize: '0.9rem' }} value={selectedClient} onChange={(e) => setSelectedClient(e.target.value)}>
              <option value="">-- {t('search')} --</option>
              {clients.map(c => <option key={c.id} value={c.id}>{c.name} (${c.currentDebt})</option>)}
            </select>
          </div>

          {/* Product grid compact */}
          <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
               <h4 style={{ fontSize: '1rem' }}>2. {t('products')} <small style={{ color: 'var(--text-muted)' }}>({filteredProducts.length})</small></h4>
               <div style={{ position: 'relative', width: '200px' }}>
                 <Search size={14} style={{ position: 'absolute', top: '10px', left: '12px', color: 'var(--text-muted)' }} />
                 <input type="text" className="form-control" style={{ paddingLeft: '35px', borderRadius: '20px', height: '34px', fontSize: '0.85rem' }} placeholder={t('search')} value={search} onChange={(e) => setSearch(e.target.value)} />
               </div>
            </div>
            
            {loading ? <div style={{ textAlign: 'center', padding: '20px' }}>{t('loading')}</div> : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '20px', maxHeight: '600px', overflowY: 'auto', paddingRight: '5px' }}>
                {groups.map(group => (
                  <div key={group}>
                    <h5 style={{ marginBottom: '10px', color: 'var(--primary)', display: 'flex', alignItems: 'center', gap: '8px', borderBottom: '1px solid var(--border-color)', paddingBottom: '5px' }}>
                      <Box size={16}/> {group}
                    </h5>
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '10px' }}>
                      {groupedProducts[group].map(p => (
                        <div 
                          key={p.id} 
                          className="card" 
                          style={{ 
                            padding: '10px 12px', cursor: 'pointer', background: 'var(--bg-surface)', border: selectedProductId === p.id ? '1px solid var(--primary)' : '1px solid var(--border-color)', 
                            transition: 'all 0.2s', boxShadow: selectedProductId === p.id ? '0 0 10px rgba(99,102,241,0.1)' : 'none'
                          }}
                          onClick={() => setSelectedProductId(selectedProductId === p.id ? null : p.id)}
                        >
                          <div style={{ display: 'flex', flexDirection: 'column', gap: '5px' }}>
                              <div style={{ fontWeight: 'bold', fontSize: '0.85rem', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{p.name}</div>
                              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                 <div style={{ fontSize: '1rem', fontWeight: 'bold', color: 'var(--primary)' }}>${p.sellPrice}</div>
                                 <button onClick={(e) => addToCart(e, p)} className="btn btn-primary" style={{ padding: '4px 8px', fontSize: '0.75rem', borderRadius: '6px' }}>+ Savat</button>
                              </div>
                              <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.7rem', color: 'var(--text-muted)', borderTop: '1px solid rgba(255,255,255,0.02)', paddingTop: '4px' }}>
                                 <span>Sklad: {p.stock}</span>
                                 <span>{p.code || 'B/K'}</span>
                              </div>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                ))}
              </div>
            )}
            {filteredProducts.length === 0 && !loading && <div style={{ textAlign: 'center', padding: '20px', color: 'var(--text-muted)' }}>Topilmadi.</div>}
          </div>
        </div>

        {/* Floating Cart section compact */}
        <div className="card" style={{ height: 'fit-content', position: 'sticky', top: '10px', display: 'flex', flexDirection: 'column', border: '2px solid var(--primary)', padding: '15px' }}>
          <h4 style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '15px', fontSize: '1rem' }}><ShoppingCart size={18} color="var(--primary)"/> {t('cart')}</h4>
          <div style={{ maxHeight: '350px', overflowY: 'auto', marginBottom: '15px' }}>
            {cart.map(item => (
              <div key={item.productId} style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '12px', borderBottom: '1px solid var(--border-color)', paddingBottom: '8px' }}>
                <div style={{ flex: 1 }}>
                  <div style={{ fontWeight: 'bold', fontSize: '0.85rem' }}>{item.name}</div>
                  <div style={{ color: 'var(--text-muted)', fontSize: '0.75rem' }}>${item.price} x {item.quantity} = <b>${item.price * item.quantity}</b></div>
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                  <input type="number" className="form-control" style={{ width: '45px', padding: '3px', fontSize: '0.8rem' }} value={item.quantity} onChange={(e) => updateQty(item.productId, e.target.value)} />
                  <button onClick={() => removeFromCart(item.productId)} style={{ color: 'var(--danger)', background: 'transparent' }}><Trash2 size={16}/></button>
                </div>
              </div>
            ))}
            {cart.length === 0 && <div style={{ color: 'var(--text-muted)', textAlign: 'center', padding: '20px', fontSize: '0.85rem' }}>{t('empty_cart')}</div>}
          </div>
          <div style={{ paddingTop: '15px', borderTop: '2px solid var(--border-color)' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '1.2rem', fontWeight: 'bold', marginBottom: '15px' }}>
              <span>{t('total')}</span>
              <span style={{ color: 'var(--primary)' }}>${total.toLocaleString()}</span>
            </div>
            <button onClick={submitOrder} disabled={loading || cart.length === 0} className="btn btn-primary" style={{ width: '100%', padding: '12px', fontWeight: 'bold' }}>
               <Send size={18}/> Yuborish
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

