import { useState, useEffect } from 'react';
import axios from 'axios';
import { API_URL } from '../constants';
import { useAuth } from '../context/AuthContext';
import { useTranslation } from '../context/LanguageContext';
import { Search, Plus, Trash2, FileUp, Edit2, ChevronDown, ChevronUp, Box, Package, LayoutGrid, List } from 'lucide-react';
import * as XLSX from 'xlsx';

export default function Products() {
  const [products, setProducts] = useState([]);
  const [search, setSearch] = useState('');
  const [selectedProductId, setSelectedProductId] = useState(null);
  const [loading, setLoading] = useState(false);
  const { user } = useAuth();
  const { t } = useTranslation();
  const isAdmin = user?.role === 'ADMIN';
  
  const [showAdd, setShowAdd] = useState(false);
  const [editProduct, setEditProduct] = useState(null);
  const [newProduct, setNewProduct] = useState({ code: '', name: '', group: '', costPrice: 0, sellPrice: 0, stock: 0, minStock: 5 });
  const [viewMode, setViewMode] = useState('grid');


  useEffect(() => { fetchProducts(); }, []);

  const fetchProducts = async () => {
    setLoading(true);
    try {
      const r = await axios.get(`${API_URL}/products`);
      setProducts(r.data || []);
    } catch (e) { console.error("Fetch error", e); }
    setLoading(false);
  };

  const handleCreate = async (e) => {
    e.preventDefault();
    try {
      await axios.post(`${API_URL}/products`, newProduct);
      alert('Saqlandi');
      fetchProducts();
      setShowAdd(false);
      setNewProduct({ code: '', name: '', group: '', costPrice: 0, sellPrice: 0, stock: 0, minStock: 5 });
    } catch (err) { alert("Xato"); }
  };

  const handleUpdate = async (e) => {
    e.preventDefault();
    try {
      await axios.put(`${API_URL}/products/${editProduct.id}`, editProduct);
      alert('Yangilandi');
      setEditProduct(null);
      fetchProducts();
    } catch (e) { alert("Xato"); }
  };

  const handleExcelImport = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    setLoading(true);
    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const data = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]]);
        const normalized = data.map(row => {
          const findKey = (keys) => {
            const rowKeys = Object.keys(row);
            for(let paramKey of keys) {
               const found = rowKeys.find(k => k.trim().toLowerCase() === paramKey.toLowerCase());
               if (found) return row[found];
            }
            return null;
          };
          return {
            code: findKey(['kodi', '╨║╨╛╨┤']) || null,
            name: findKey(['nomi', '╨╜╨░╨╕╨╝╨╡╨╜╨╛╨▓╨░╨╜╨╕╨╡']),
            group: findKey(['guruh', '╨│╤Ç╤â╨┐╨┐╨░']) || 'Boshqa',
            costPrice: parseFloat(findKey(['tannarx', '╤ü╨╡╨▒╨╡╤ü╤é╨╛╨╕╨╝╨╛╤ü╤é╤î'])) || 0,
            sellPrice: parseFloat(findKey(['sotish', '╤å╨╡╨╜╨░'])) || 0,
            stock: parseInt(findKey(['sklad', '╨╛╤ü╤é╨░╤é╨╛╨║'])) || 0
          };
        });
        await axios.post(`${API_URL}/products/bulk`, { products: normalized });
        fetchProducts();
        alert("Tayyor!");
      } catch (err) { alert("Xato"); }
      setLoading(false);
    };
    reader.readAsBinaryString(file);
  };

  const deleteProduct = (e, id) => {
    e.stopPropagation();
    if (!window.confirm("O'chirishni tasdiqlaysizmi?")) return;
    axios.delete(`${API_URL}/products/${id}`).then(() => fetchProducts());
  };

  // ROBUST SEARCH & GROUPING
  const s = search.toLowerCase();
  const filtered = products.filter(p => 
    String(p.name || '').toLowerCase().includes(s) || 
    String(p.code || '').toLowerCase().includes(s) || 
    String(p.group || '').toLowerCase().includes(s)
  );

  const grouped = filtered.reduce((acc, p) => {
    const g = p.group || 'Boshqa';
    if (!acc[g]) acc[g] = [];
    acc[g].push(p);
    return acc;
  }, {});

  const groups = Object.keys(grouped).sort();

  return (
    <div className="animate-fade-in">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '25px', flexWrap: 'wrap', gap: '15px' }}>
        <h2>≡ƒôª {t('products')} <small style={{ color: 'var(--text-muted)' }}>({products.length})</small></h2>
        <div style={{ display: 'flex', gap: '10px' }}>
          <div style={{ display: 'flex', background: 'var(--bg-surface)', borderRadius: '8px', padding: '2px', marginRight: '5px' }}>
            <button onClick={() => setViewMode('grid')} className="btn" style={{ padding: '6px 10px', background: viewMode === 'grid' ? 'var(--primary)' : 'transparent', color: viewMode === 'grid' ? '#fff' : 'inherit', border: 'none', borderRadius: '6px', cursor: 'pointer' }}><LayoutGrid size={16}/></button>
            <button onClick={() => setViewMode('list')} className="btn" style={{ padding: '6px 10px', background: viewMode === 'list' ? 'var(--primary)' : 'transparent', color: viewMode === 'list' ? '#fff' : 'inherit', border: 'none', borderRadius: '6px', cursor: 'pointer' }}><List size={16}/></button>
          </div>
          <div style={{ position: 'relative', width: '220px' }}>
            <Search size={16} style={{ position: 'absolute', top: '10px', left: '12px', color: 'var(--text-muted)' }} />
            <input type="text" className="form-control" placeholder="Model, guruh yoki kod..." style={{ paddingLeft: '35px', borderRadius: '20px', height: '36px', fontSize: '0.85rem' }} value={search} onChange={e => setSearch(e.target.value)} />
          </div>
          <button onClick={() => { setEditProduct(null); setShowAdd(!showAdd); }} className="btn btn-primary" style={{ padding: '8px 15px', fontSize: '0.85rem' }}><Plus size={16}/> Qo'shish</button>
          <label className="btn btn-secondary" style={{ cursor: 'pointer', padding: '8px 15px', fontSize: '0.85rem', display: 'flex', alignItems: 'center', gap: '6px' }}>
            <FileUp size={16} /> Excel
            <input type="file" hidden accept=".xlsx,.xls" onChange={handleExcelImport} />
          </label>
        </div>
      </div>

      {(showAdd || editProduct) && (
        <div className="card glass-panel" style={{ marginBottom: '25px', padding: '20px', borderLeft: '5px solid var(--primary)' }}>
          <h3>{editProduct ? 'Tahrirlash' : 'Yangi Mahsulot'}</h3>
          <form onSubmit={editProduct ? handleUpdate : handleCreate} className="responsive-grid" style={{ marginTop: '15px' }}>
             <div className="form-group"><label>Nomi *</label><input type="text" className="form-control" value={editProduct ? editProduct.name : newProduct.name} onChange={e => editProduct ? setEditProduct({...editProduct, name: e.target.value}) : setNewProduct({...newProduct, name: e.target.value})} required/></div>
             <div className="form-group"><label>Guruh (Model)</label><input type="text" className="form-control" value={editProduct ? editProduct.group : newProduct.group} onChange={e => editProduct ? setEditProduct({...editProduct, group: e.target.value}) : setNewProduct({...newProduct, group: e.target.value})} placeholder="Samsung, Honor, Redmi..."/></div>
             <div className="form-group"><label>Kodi</label><input type="text" className="form-control" value={editProduct ? editProduct.code : newProduct.code} onChange={e => editProduct ? setEditProduct({...editProduct, code: e.target.value}) : setNewProduct({...newProduct, code: e.target.value})}/></div>
             <div className="form-group"><label>Sklad (Soni)</label><input type="number" className="form-control" value={editProduct ? editProduct.stock : newProduct.stock} onChange={e => editProduct ? setEditProduct({...editProduct, stock: e.target.value}) : setNewProduct({...newProduct, stock: e.target.value})}/></div>
             <div className="form-group"><label>Tannarx ($)</label><input type="number" step="0.01" className="form-control" value={editProduct ? editProduct.costPrice : newProduct.costPrice} onChange={e => editProduct ? setEditProduct({...editProduct, costPrice: e.target.value}) : setNewProduct({...newProduct, costPrice: e.target.value})}/></div>
             <div className="form-group"><label>Sotish ($)</label><input type="number" step="0.01" className="form-control" value={editProduct ? editProduct.sellPrice : newProduct.sellPrice} onChange={e => editProduct ? setEditProduct({...editProduct, sellPrice: e.target.value}) : setNewProduct({...newProduct, sellPrice: e.target.value})}/></div>
             <div style={{ gridColumn: '1 / -1', display: 'flex', gap: '10px' }}>
                <button type="submit" className="btn btn-primary" style={{ flex: 1, padding: '12px' }}>{editProduct ? 'Yangilash' : 'Saqlash'}</button>
                <button type="button" onClick={() => { setShowAdd(false); setEditProduct(null); }} className="btn btn-secondary" style={{ flex: 1, padding: '12px' }}>Bekor qilish</button>
             </div>
          </form>
        </div>
      )}

      {loading ? <div style={{ textAlign: 'center', padding: '40px' }}>{t('loading')}</div> : (
        viewMode === 'list' ? (
          <div className="table-container card" style={{ padding: '0' }}>
            <table className="custom-table">
              <thead>
                <tr>
                  <th>Mahsulot Nomi</th>
                  <th>Guruh</th>
                  <th>Kod</th>
                  <th>Sklad</th>
                  <th>Tannarx ($)</th>
                  <th>Sotish ($)</th>
                  {isAdmin && <th>Amallar</th>}
                </tr>
              </thead>
              <tbody>
                {filtered.map(p => (
                  <tr key={p.id} onClick={() => setSelectedProductId(p.id)} style={{ background: selectedProductId === p.id ? 'rgba(99,102,241,0.05)' : 'transparent', cursor: 'pointer' }}>
                    <td><div style={{ fontWeight: '600' }}>{p.name}</div></td>
                    <td>{p.group || 'ΓÇö'}</td>
                    <td><code style={{ fontSize: '0.8rem', opacity: 0.7 }}>{p.code || 'ΓÇö'}</code></td>
                    <td>
                      <span className={`badge ${p.stock <= p.minStock ? 'badge-danger' : 'badge-success'}`}>
                        {p.stock} dona
                      </span>
                    </td>
                    <td>${p.costPrice}</td>
                    <td><b style={{ color: 'var(--primary)' }}>${p.sellPrice}</b></td>
                    {isAdmin && (
                      <td>
                        <div style={{ display: 'flex', gap: '10px' }}>
                          <button onClick={(e) => { e.stopPropagation(); setEditProduct(p); setShowAdd(true); window.scrollTo(0,0); }} style={{ color: 'var(--primary)', background: 'transparent', border: 'none', cursor: 'pointer' }}><Edit2 size={16}/></button>
                          <button onClick={(e) => deleteProduct(e, p.id)} style={{ color: 'var(--danger)', background: 'transparent', border: 'none', cursor: 'pointer' }}><Trash2 size={16}/></button>
                        </div>
                      </td>
                    )}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '30px' }}>
            {groups.map(group => (
              <div key={group}>
                <h3 style={{ marginBottom: '15px', color: 'var(--text-muted)', display: 'flex', alignItems: 'center', gap: '10px', fontSize: '1.2rem', paddingBottom: '10px', borderBottom: '1px solid var(--border-color)' }}>
                  <Box size={20} color="var(--primary)"/> {group}
                </h3>
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '15px' }}>
                  {grouped[group].map(p => (
                    <div key={p.id} className="card" onClick={() => setSelectedProductId(p.id)} style={{ 
                      padding: '15px', display: 'flex', flexDirection: 'column', gap: '12px', 
                      borderLeft: '4px solid var(--primary)', cursor: 'pointer', transition: 'all 0.2s',
                      background: selectedProductId === p.id ? 'var(--bg-hover)' : 'var(--bg-surface)',
                      boxShadow: selectedProductId === p.id ? '0 4px 12px rgba(99,102,241,0.15)' : 'none'
                    }}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                        <h4 style={{ margin: 0, fontSize: '1.05rem', fontWeight: 'bold', color: 'var(--text-color)' }}>{p.name}</h4>
                        <span style={{ fontSize: '0.75rem', background: 'rgba(255,255,255,0.05)', padding: '3px 8px', borderRadius: '12px', color: 'var(--text-muted)', border: '1px solid var(--border-color)' }}>{p.code || 'B/K'}</span>
                      </div>
                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '5px' }}>
                         <div style={{ display: 'flex', flexDirection: 'column' }}>
                            <span style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>Sotish narxi</span>
                            <span style={{ fontSize: '1.25rem', fontWeight: 'bold', color: 'var(--primary)' }}>${p.sellPrice}</span>
                         </div>
                         <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end' }}>
                            <span style={{ fontSize: '0.8rem', color: 'var(--text-muted)', marginBottom: '4px' }}>Sklad qoldig'i</span>
                            <span className={`badge ${p.stock <= p.minStock ? 'badge-danger' : 'badge-success'}`} style={{ fontSize: '0.85rem', padding: '4px 8px' }}>{p.stock} dona</span>
                         </div>
                      </div>
                      {isAdmin && (
                        <div style={{ borderTop: '1px solid var(--border-color)', paddingTop: '12px', display: 'flex', justifyContent: 'flex-end', gap: '8px', marginTop: 'auto' }}>
                          <button onClick={(e) => { e.stopPropagation(); setEditProduct(p); setShowAdd(true); window.scrollTo(0,0); }} className="btn" style={{ padding: '6px 12px', color: 'var(--primary)', background: 'rgba(99,102,241,0.1)', border: 'none', borderRadius: '6px', cursor: 'pointer' }}><Edit2 size={16}/></button>
                          <button onClick={(e) => deleteProduct(e, p.id)} className="btn" style={{ padding: '6px 12px', color: 'var(--danger)', background: 'rgba(239,68,68,0.1)', border: 'none', borderRadius: '6px', cursor: 'pointer' }}><Trash2 size={16}/></button>
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>
        )
      )}
      {filtered.length === 0 && !loading && <div className="card" style={{ textAlign: 'center', padding: '40px', color: 'var(--text-muted)' }}>Mahsulot topilmadi.</div>}
    </div>
  );
}

import { useState } from 'react';
import axios from 'axios';
import { API_URL } from '../constants';
import { useAuth } from '../context/AuthContext';
import { Settings as SettingsIcon, Shield, RefreshCw } from 'lucide-react';

export default function Settings() {
  const { user, login } = useAuth();
  const [newPassword, setNewPassword] = useState('');
  const [loading, setLoading] = useState(false);

  const updatePassword = async (e) => {
    e.preventDefault();
    if (!newPassword || newPassword.length < 4) return alert("Parol juda qisqa!");
    setLoading(true);
    try {
      await axios.put(`${API_URL}/admin/agents/${user.id}`, { password: newPassword });
      alert("Parol o'zgartirildi!");
      setNewPassword('');
    } catch (err) {
      alert("Xato: O'zgartirib bo'lmadi");
    }
    setLoading(false);
  };

  return (
    <div className="animate-fade-in">
      <div style={{ display: 'flex', gap: '20px', alignItems: 'start' }}>
        <div className="card" style={{ flex: 1, maxWidth: '500px' }}>
          <h3 style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '20px' }}>
            <SettingsIcon color="var(--primary)" /> Shaxsiy Sozlamalar
          </h3>
          
          <form onSubmit={updatePassword}>
            <div className="form-group">
              <label>Yangi Parol o'rnatish</label>
              <div style={{ position: 'relative' }}>
                <Shield size={18} style={{ position: 'absolute', top: '12px', left: '15px', color: 'var(--text-muted)' }} />
                <input 
                  type="password" 
                  className="form-control" 
                  style={{ paddingLeft: '45px' }}
                  value={newPassword}
                  onChange={e => setNewPassword(e.target.value)}
                  placeholder="Yangi parol..."
                  required
                />
              </div>
            </div>
            
            <button type="submit" disabled={loading} className="btn btn-primary" style={{ marginTop: '10px' }}>
              <RefreshCw size={16} /> Parolni Yangilash
            </button>
          </form>
          
          <div style={{ marginTop: '30px', padding: '15px', background: 'rgba(255,255,255,0.03)', borderRadius: '8px', fontSize: '0.85rem', color: 'var(--text-muted)' }}>
            Eslatma: Administrator barcha agentlarning parolini "Agentlar" bo'limidan ham yangilashi mumkin.
          </div>
        </div>
      </div>
    </div>
  );
}
